		}

		if (send_status != LDNS_STATUS_OK) {
			ldns_resolver_set_nameserver_rtt(r, i, LDNS_RESOLV_RTT_INF);
			status = send_status;
		}
		if(reply_bytes && ldns_buffer_limit(qb) >= 2) {
			uint16_t txid = ldns_buffer_read_u16_at(qb, 0);
			if(reply_size < 2 ||
				ldns_read_uint16(reply_bytes) != txid) {
				status = LDNS_STATUS_ID_DID_NOT_MATCH;
				LDNS_FREE(reply_bytes);
				reply_bytes = NULL;
				reply_size = 0;
			}
		}

		/* obey the fail directive */
		if (!reply_bytes) {
			/* the current nameserver seems to have a problem, blacklist it */
			if (ldns_resolver_fail(r)) {
				if(src) {
					LDNS_FREE(src);
				}
				LDNS_FREE(ns);
				return status ? status : LDNS_STATUS_ERR;
			} else {
				LDNS_FREE(ns);
				continue;
			}
		} 

		status = ldns_wire2pkt(&reply, reply_bytes, reply_size);
		if (status != LDNS_STATUS_OK) {
			if(src) LDNS_FREE(src);
			LDNS_FREE(reply_bytes);
			LDNS_FREE(ns);
			return status;
		}
		assert(reply);

		LDNS_FREE(ns);
		gettimeofday(&tv_e, NULL);

		if (reply) {
			ldns_pkt_set_querytime(reply, (uint32_t)
				((tv_e.tv_sec - tv_s.tv_sec) * 1000) +
				(tv_e.tv_usec - tv_s.tv_usec) / 1000);
			ldns_pkt_set_answerfrom(reply,
					ldns_rdf_clone(ns_array[i]));
			ldns_pkt_set_timestamp(reply, tv_s);
			ldns_pkt_set_size(reply, reply_size);
			break;
		} else {
			if (ldns_resolver_fail(r)) {
				/* if fail is set bail out, after the first
				 * one */
				break;
			}
		}

		/* wait retrans seconds... */
		sleep((unsigned int) ldns_resolver_retrans(r));
	}

	if(src) {
		LDNS_FREE(src);
	}
	if (all_servers_rtt_inf) {
		LDNS_FREE(reply_bytes);
		return LDNS_STATUS_RES_NO_NS;
	}
#ifdef HAVE_SSL
	if (tsig_mac && reply && reply_bytes) {
		if (!ldns_pkt_tsig_verify(reply,
		                          reply_bytes,
					  reply_size,
		                          ldns_resolver_tsig_keyname(r),
		                          ldns_resolver_tsig_keydata(r), tsig_mac)) {
			status = LDNS_STATUS_CRYPTO_TSIG_BOGUS;
		}
	}
#else
	(void)tsig_mac;
#endif /* HAVE_SSL */

	LDNS_FREE(reply_bytes);
	if (reply) {
		ldns_pkt *query = NULL;

		if(ldns_pkt_qdcount(reply) != 1) {
			status = LDNS_STATUS_QDCOUNT_MUST_BE_ONE;
			ldns_pkt_free(reply);
			reply = NULL;

		} else if(ldns_wire2pkt(&query
		                , ldns_buffer_begin(qb)
		                , ldns_buffer_position(qb)) != LDNS_STATUS_OK
		|| ldns_pkt_qdcount(query) != 1
		|| ldns_rr_compare(ldns_rr_list_rr(ldns_pkt_question(query),0)
		                  ,ldns_rr_list_rr(ldns_pkt_question(reply),0))){
			status = LDNS_STATUS_QUERY_DID_NOT_MATCH;
			ldns_pkt_free(reply);
			reply = NULL;
		}
		ldns_pkt_free(query);
	}
	if (result) {
		*result = reply;
	}

	return status;
}
